css:
.loader {color: var(--loader-color, #2563eb);
  --loader-secondary-color: #38bdf8;
  --loader-bg: #ffffff;
  height: 64px;
  aspect-ratio: 2;
  display: grid;
  grid-template-columns: 1fr 1fr;
}.loader:before,.loader:after {content: "";
  border: 8px solid var(--loader-color, #2563eb);
  box-sizing: content-box;
  margin: auto;
  aspect-ratio: 1;
  animation:l10-0 infinite .5s steps(4,jump-none) alternate,l10-1 infinite 2s steps(2,jump-none);
}.loader:before {animation-delay: -.3s;
}@keyframes l10-0 {0% {width: 0% }to {width: 75%}}@keyframes l10-1 {0% {border-radius: 0% }to {border-radius: 100%}}
